&CreRecPag = 'P'
If &Mode <> TrnMode.Display If &Mode <> TrnMode.Delete RetornaAutorizacao.Call('WWLOCALCOBRANCA', Status_SimNao.Sim, 2, &AutNiv) Else RetornaAutorizacao.Call('WWLOCALCOBRANCA', Status_SimNao.Sim, 3, &AutNiv) EndIF Endif
